  ('diplomatic-5118c8cd-moex-00230', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-111-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '1982年8月17日，時任美國國務卿喬治．舒茲發送給時任美國在臺協會處長李潔明，該電報揭示「對 臺六項保證」，下列何者不是六項保證的內容？', '["未同意設定終止對臺軍售的日期", "未同意就對臺軍售議題向中華人民共和國徵詢意見", "未改變關於臺灣主權的立場", "未改變要求臺灣與中華人民共和國進行和平談判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
